// Process heterogeneous array from Merge node
const items = $input.all().map(i => i.json);

let analisis7d = [], ultimo = null, vencidas = [], hitos = [], eventos = [], recos = [], destinatarios = [], backCommits = [], frontCommits = [];

// Helper: detect object type by structure
const detectType = (obj) => {
  if (!obj || typeof obj !== 'object') return 'unknown';

  if (obj.progreso_pct !== undefined) return 'analisis';
  if (obj.card_id && obj.card_nombre) return 'tarea';
  if (obj.email && obj.nombre) return 'destinatario';
  if (obj.sha && obj.commit) return 'commit';
  // CORRECCIÓN AQUÍ:
  if (obj.fecha_fin && obj.tipo && !obj.card_id) return 'hito'; 
  if (obj.descripcion && obj.tipo) {
      // Diferenciar entre evento y recomendación por contenido o tabla si es posible
      return obj.aplicada !== undefined ? 'recomendacion' : 'evento';
  }

  return 'unknown';
};

// Segregate: Merge data is heterogeneous array
for (const obj of items) {
  const type = detectType(obj);

  if (type === 'analisis') {
    analisis7d.push(obj);
  } else if (type === 'tarea') {
    vencidas.push(obj);
  } else if (type === 'destinatario') {
    destinatarios.push(obj);
  } else if (type === 'commit') {
    // Guess backend vs frontend by repo in commit message or branch hint
    const msg = obj.commit?.message || '';
    if (msg.toLowerCase().includes('front') || msg.toLowerCase().includes('ui') || msg.toLowerCase().includes('component')) {
      frontCommits.push(obj);
    } else {
      backCommits.push(obj);
    }
  } else if (type === 'hito') {
    hitos.push(obj);
  } else if (type === 'recomendacion') {
    recos.push(obj);
  } else if (type === 'evento') {
    eventos.push(obj);
  }
}

// Sort análisis by date DESC to get latest first
analisis7d.sort((a, b) => new Date(b.fecha_ejecucion) - new Date(a.fecha_ejecucion));
ultimo = analisis7d[0] || {};

// Parse KPIs if string
const k = ultimo.kpis_json || {};
const kpis = typeof k === 'string' ? JSON.parse(k) : k;

// Calculate trend
const tendencia = analisis7d.length > 1 ? {
  progreso_inicial: analisis7d[analisis7d.length - 1]?.progreso_pct || 0,
  progreso_final: analisis7d[0]?.progreso_pct || 0,
  delta: (analisis7d[0]?.progreso_pct || 0) - (analisis7d[analisis7d.length - 1]?.progreso_pct || 0),
  ejecuciones: analisis7d.length
} : null;

const prompt = `Genera un RESUMEN EJECUTIVO del reporte semanal del proyecto PetSafe (sistema veterinario). Usa tono profesional en español. Estructura:

1. ESTADO GENERAL (1 párrafo, 3-4 frases)
2. LOGROS DE LA SEMANA (bullets, máx 4)
3. RIESGOS CRÍTICOS (bullets con prioridad A/M/B, máx 4)
4. PRÓXIMOS PASOS (bullets accionables, máx 4)

Datos:
${JSON.stringify({
  kpis,
  tendencia,
  ultimo: {
    progreso_pct: ultimo.progreso_pct,
    total_tareas: ultimo.total_tareas,
    tareas_completadas: ultimo.tareas_completadas,
    tareas_vencidas: ultimo.tareas_vencidas,
    cantidad_problemas: ultimo.cantidad_problemas
  },
  vencidas_count: vencidas.length,
  hitos_proximos: hitos.slice(0, 3),
  commits: { back: backCommits.length, front: frontCommits.length },
  eventos_count: eventos.length
})}

Responde SOLO con HTML válido usando <h3>, <p>, <ul>, <li>, <strong>. Sin backticks ni markdown.`;

const data = {
  fecha_reporte: new Date().toISOString(),
  fecha_reporte_local: new Date().toLocaleString('es-EC', { timeZone: 'America/Guayaquil' }),
  rango_dias: $node['Configuración'].json.rango_dias,
  ultimo_analisis: ultimo,
  kpis,
  tendencia,
  analisis_historia: analisis7d,
  tareas_vencidas: vencidas,
  hitos_proximos: hitos,
  eventos_recientes: eventos,
  recomendaciones_pendientes: recos,
  destinatarios: destinatarios.map(d => d.email),
  destinatarios_info: destinatarios,
  commits_back: backCommits.map(c => ({ sha: (c.sha || '').substring(0,7), autor: c.commit?.author?.name, fecha: c.commit?.author?.date, mensaje: (c.commit?.message || '').split('\n')[0] })),
  commits_front: frontCommits.map(c => ({ sha: (c.sha || '').substring(0,7), autor: c.commit?.author?.name, fecha: c.commit?.author?.date, mensaje: (c.commit?.message || '').split('\n')[0] })),
  total_commits_back: backCommits.length,
  total_commits_front: frontCommits.length,
  gemini_key: $env.GEMINI_API_KEY,
  prompt
};

return [{ json: data }];

const gem = $json;
const data = $node['Build Report Data'].json;
const summaryHtml = gem?.candidates?.[0]?.content?.parts?.[0]?.text?.trim() || 
  `<p><strong>Estado del proyecto:</strong> Progreso ${data.ultimo_analisis.progreso_pct || 0}% · Equipo activo · ${data.tareas_vencidas.length} tareas vencidas · Proyección: ${data.kpis.proyeccion_a_tiempo ? 'A tiempo' : 'En riesgo'}</p>
   <p><strong>Focus:</strong> ${data.kpis.dias_hasta_fin} días hasta fin. Velocidad ${data.kpis.velocidad_tareas_por_dia || 0}/día.</p>`; 

const fmt = (d) => d ? new Date(d).toLocaleDateString('es-EC', { timeZone: 'America/Guayaquil' }) : '-';
const esc = (s) => String(s ?? '').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

const k = data.kpis || {};
const rowsKpis = [
  ['Progreso general', `${data.ultimo_analisis.progreso_pct || 0}%`],
  ['Velocidad (tareas/sem)', k.velocidad_semana ?? '-'],
  ['% Tareas a tiempo', (k.pct_a_tiempo != null ? k.pct_a_tiempo + '%' : '-')],
  ['Commits/día (back)', k.commits_por_dia_back ?? '-'],
  ['Commits/día (front)', k.commits_por_dia_front ?? '-'],
  ['PR open time (h) back', k.pr_open_time_back ?? '-'],
  ['PR open time (h) front', k.pr_open_time_front ?? '-'],
  ['PR merge ratio', k.pr_merge_ratio ?? '-'],
  ['Días restantes', k.dias_hasta_fin ?? '-'],
  ['Proyección a tiempo', k.proyeccion_a_tiempo ? 'Sí' : 'En riesgo']
];

const trHtml = (arr) => arr.map(r => `<tr><td>${esc(r[0])}</td><td><strong>${esc(r[1])}</strong></td></tr>`).join('');

const vencidasHtml = data.tareas_vencidas.length ? `<table><thead><tr><th>Tarea</th><th>Lista</th><th>Responsable</th><th>Vencida el</th></tr></thead><tbody>${data.tareas_vencidas.map(v => `<tr><td>${esc(v.card_nombre)}</td><td>${esc(v.lista_nombre)}</td><td>${esc(v.miembro_nombre || '-')}</td><td>${fmt(v.fecha_vencimiento)}</td></tr>`).join('')}</tbody></table>` : '<p><em>Sin tareas vencidas.</em></p>';

const hitosHtml = data.hitos_proximos.length ? `<table><thead><tr><th>Hito</th><th>Tipo</th><th>Fecha</th><th>Responsable</th></tr></thead><tbody>${data.hitos_proximos.map(h => `<tr><td>${esc(h.nombre)}</td><td>${esc(h.tipo)}</td><td>${fmt(h.fecha_fin)}</td><td>${esc(h.responsable || '-')}</td></tr>`).join('')}</tbody></table>` : '';

const commitsHtml = (arr, titulo) => {
  if (!arr.length) return '';
  const lines = arr.slice(0, 10).map(c => {
    const author = esc(c.autor).split(' ')[0];
    const msg = esc(c.mensaje).slice(0, 70);
    const date = fmt(c.fecha);
    return `<div style="margin-bottom:3mm; font-size:9.5pt;"><code>${esc(c.sha)}</code> ${author}: ${msg} · ${date}</div>`;
  }).join('');
  return `<h4>${titulo}</h4>${lines}`;
};

const eventosHtml = data.eventos_recientes.length ? `<ul>${data.eventos_recientes.slice(0, 15).map(e => `<li>${fmt(e.fecha)} — <strong>${esc(e.tipo)}</strong>: ${esc(e.descripcion)}</li>`).join('')}</ul>` : '';

const recosHtml = data.recomendaciones_pendientes.length ? `<ul>${data.recomendaciones_pendientes.slice(0, 10).map(r => `<li>${fmt(r.fecha)} — ${esc((r.descripcion || '').substring(0, 300))}</li>`).join('')}</ul>` : '';

const tendenciaHtml = data.tendencia ? `<p>Progreso: <strong>${data.tendencia.progreso_inicial}%</strong> → <strong>${data.tendencia.progreso_final}%</strong> (Δ ${data.tendencia.delta >= 0 ? '+' : ''}${data.tendencia.delta} pts · ${data.tendencia.ejecuciones} ejecuciones)</p>` : '<p><em>Datos insuficientes para tendencia.</em></p>';

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="utf-8"/>
<title>Reporte Semanal PetSafe</title>
<style>
  @page { margin: 22mm 18mm; }
  body { font-family: 'Helvetica', Arial, sans-serif; color: #222; font-size: 11pt; line-height: 1.4; }
  .portada { text-align: center; padding: 40mm 0 30mm; border-bottom: 3px solid #1e40af; margin-bottom: 20mm; }
  .portada h1 { color: #1e40af; font-size: 28pt; margin: 0 0 6mm; }
  .portada h2 { color: #555; font-size: 14pt; font-weight: normal; margin: 0 0 10mm; }
  .portada .meta { color: #777; font-size: 10pt; }
  h2 { color: #1e40af; border-bottom: 2px solid #1e40af; padding-bottom: 2mm; margin-top: 12mm; font-size: 14pt; }
  h3 { color: #333; font-size: 12pt; margin-top: 6mm; }
  h4 { color: #555; font-size: 11pt; margin-top: 4mm; }
  table { width: 100%; border-collapse: collapse; margin: 4mm 0; font-size: 10pt; }
  th { background: #1e40af; color: white; padding: 2mm; text-align: left; }
  td { padding: 2mm; border-bottom: 1px solid #ddd; }
  tr:nth-child(even) td { background: #f7f7fb; }
  ul { margin: 2mm 0; padding-left: 6mm; }
  li { margin-bottom: 1mm; }
  code { background: #eef; padding: 0 1mm; border-radius: 2px; font-size: 9pt; }
  .footer { margin-top: 20mm; padding-top: 3mm; border-top: 1px solid #ccc; color: #888; font-size: 9pt; text-align: center; }
  .badge { display: inline-block; padding: 1mm 3mm; border-radius: 3px; font-size: 9pt; font-weight: bold; }
  .badge-ok { background: #16a34a; color: white; }
  .badge-warn { background: #eab308; color: white; }
  .badge-err { background: #dc2626; color: white; }
</style>
</head>
<body>
<div class="portada">
  <h1>🐾 PetSafe</h1>
  <h2>Reporte Semanal de Gestión</h2>
  <div class="meta">Generado: ${esc(data.fecha_reporte_local)}<br/>Rango: últimos ${data.rango_dias} días</div>
</div>

<h2>1. Resumen Ejecutivo</h2>
${summaryHtml}

<h2>2. KPIs del Proyecto</h2>
<table><thead><tr><th>Indicador</th><th>Valor</th></tr></thead><tbody>${trHtml(rowsKpis)}</tbody></table>

<h2>3. Tendencia Semanal</h2>
${tendenciaHtml}

<h2>4. Tareas Vencidas</h2>
${vencidasHtml}

${data.hitos_proximos.length ? '<h2>5. Hitos Próximos (30 días)</h2>' : ''}
${hitosHtml}

<h2>6. Actividad Git</h2>
${commitsHtml(data.commits_back, 'Backend')}
${commitsHtml(data.commits_front, 'Frontend')}

${data.eventos_recientes.length ? '<h2>7. Eventos Detectados</h2>' : ''}
${eventosHtml}

${data.recomendaciones_pendientes.length ? '<h2>8. Recomendaciones Pendientes (IA)</h2>' : ''}
${recosHtml}

<div class="footer">🤖 Reporte generado automáticamente por n8n + Gemini · PetSafe PM Assistant</div>
</body>
</html>`;

const fileName = `reporte-petsafe-${new Date().toISOString().slice(0,10)}.html`;
const summaryText = `Reporte semanal PetSafe: progreso ${data.ultimo_analisis.progreso_pct || 0}%, ${data.tareas_vencidas.length} tareas vencidas, ${data.total_commits_back + data.total_commits_front} commits, ${data.eventos_recientes.length} eventos.`;

return [{
  json: {
    summaryText,
    destinatarios: data.destinatarios,
    destinatarios_info: data.destinatarios_info,
    rango_dias: data.rango_dias,
    fecha_reporte_local: data.fecha_reporte_local
  },
  binary: {
    data: {
      data: Buffer.from(html).toString('base64'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];

const meta = $node['Build HTML + Binary'].json;
const fileName = `reporte-petsafe-${new Date().toISOString().slice(0,10)}.pdf`;
const pdfBin = $binary.pdf;
return [{
  json: { ...meta, fileName },
  binary: { pdf: { ...pdfBin, fileName, mimeType: 'application/pdf' } }
}];
